prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?org ?orgName (COUNT(?model) as ?modelCount) WHERE {
  ?org a bboExt:Organization .
  OPTIONAL { ?org bbo:name ?orgName . }
  OPTIONAL { ?org rdfs:label ?orgName . }
  OPTIONAL {
    ?model a bboExt:Model .
    ?model tai:belongsTo ?org .
  }
}
GROUP BY ?org ?orgName
ORDER BY DESC(?modelCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName ?defs ?model ?modelName ?org ?orgName WHERE {
  ?elem bbo:name "Admissions Officer" .
  ?elem a bboExt:Participant .
  ?elem tai:belongsTo ?choreo .
  ?choreo a bboExt:Choreography .
  ?choreo bbo:name ?choreoName .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  OPTIONAL { ?org a bboExt:Organization . }
  OPTIONAL { ?org bbo:name ?orgName . }
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName ?defs ?defsType ?model ?modelType ?modelName ?org ?orgType ?orgName WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo bbo:name ?choreoName .
  ?choreo tai:belongsTo ?defs .
  ?defs a ?defsType .
  ?defs tai:belongsTo ?model .
  ?model a ?modelType .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    ?org a ?orgType .
    OPTIONAL { ?org bbo:name ?orgName . }
  }
}
LIMIT 20

